function solve(matrix) {
    const n = matrix.length;
    const ans = new Array(n).fill(0);

    for (let i = 0; i < n; i++) {
        let degree = 0;
        for (let j = 0; j < n; j++) {
            if (matrix[i][j] === 1) {
                // Since matrix[i][i] is guaranteed to be 0, we don't need to explicitly check i !== j,
                // but it's conceptually correct that we are counting neighbors.
                degree++;
            }
        }
        ans[i] = degree;
    }

    return ans;
}
